// ─── Data Processing ───
function expandData(raw) {
  return raw.map(d => {
    const po = d.p || '';
    const isFuji = po.startsWith('ANC') || po.startsWith('A&C') || po.startsWith('FBAU');
    const customer = isFuji ? 'Fuji' : 'Droppoint';
    
    // Calculate SLA based on speed and distance
    let slaMins = 0;
    if (d.sp === 'VIP') {
      if (d.dk <= 30) slaMins = 90;
      else if (d.dk <= 50) slaMins = 120;
      else slaMins = 150;
    } else if (d.sp === '3 hour') {
      slaMins = 180;
    }
    // Same day = delivery prior to requested drop time
    
    // Parse times
    const reqPickup = d.rp ? new Date(d.rp) : null;
    const reqDrop = d.rd ? new Date(d.rd) : null;
    const actualDrop = d.dra ? new Date(d.dra) : null;
    const bookingDate = d.d ? new Date(d.d) : null;
    
    // Calculate expected delivery for VIP and 3-hour
    let expectedDelivery = null;
    if (d.sp === 'Same day') {
      expectedDelivery = reqDrop;
    } else if (reqPickup && slaMins > 0) {
      expectedDelivery = new Date(reqPickup.getTime() + slaMins * 60000);
    }
    
    // Parse attempt timestamps (comma-separated ISO strings in the "at" field)
    const attempts = (d.at || '').split(',').map(s => s.trim()).filter(Boolean).map(s => new Date(s)).filter(dt => !isNaN(dt.getTime()));
    const attemptCount = attempts.length;
    const firstAttemptTime = attempts.length > 0 ? attempts.reduce((a, b) => a < b ? a : b) : null;

    // Calculate if late
    let isLate = false;
    let delayMins = 0;
    if (actualDrop && expectedDelivery) {
      delayMins = (actualDrop - expectedDelivery) / 60000;
      isLate = delayMins > 0;
    }

    // If late based on actual drop, check if first attempt was within SLA
    // If the attempt was created within the SLA deadline, the booking counts as "On Time"
    let attemptWithinSLA = false;
    if (isLate && firstAttemptTime && expectedDelivery) {
      attemptWithinSLA = firstAttemptTime <= expectedDelivery;
      if (attemptWithinSLA) {
        isLate = false;
        delayMins = 0;
      }
    }
    
    // Booking to pickup time
    let bookingToPickupMins = null;
    if (reqPickup && bookingDate) {
      // hour field is the booking hour
      const bookingTime = new Date(bookingDate);
      bookingTime.setHours(d.h, 0, 0, 0);
      // Use requested pickup as reference for booking->pickup
    }
    
    // Pickup to delivery time
    let pickupToDeliveryMins = null;
    if (reqPickup && actualDrop) {
      pickupToDeliveryMins = (actualDrop - reqPickup) / 60000;
    }
    
    // Booking to pickup (using requested pickup time as when it was booked/assigned)
    let bookingToPickup = null;
    if (reqPickup && bookingDate) {
      const bTime = new Date(bookingDate);
      bTime.setHours(d.h, 0, 0, 0);
      bookingToPickup = (reqPickup - bTime) / 60000;
    }

    return {
      bookingRef: d.r,
      po: po,
      courier: d.c,
      pickupAddress: d.pa,
      dropAddress: d.da,
      date: d.d,
      state: d.st,
      speed: d.sp,
      distanceKm: d.dk,
      hour: d.h,
      status: d.s,
      requestedDrop: d.rd,
      requestedPickup: d.rp,
      dropActual: d.dra,
      attempted: d.at,
      attempts,
      attemptCount,
      firstAttemptTime,
      attemptWithinSLA: d.s === 'Dropped Off' ? attemptWithinSLA : false,
      customer,
      slaMins,
      expectedDelivery,
      isLate: d.s === 'Dropped Off' ? isLate : false,
      isOnTime: d.s === 'Dropped Off' ? !isLate : false,
      delayMins: d.s === 'Dropped Off' ? Math.max(0, delayMins) : 0,
      pickupToDeliveryMins,
      bookingToPickup,
    };
  });
}

function expandNotes(raw) {
  return raw.filter(n => n.n).map(n => ({
    bookingRef: n.r,
    note: n.n,
    author: n.a || 'System',
    timestamp: n.t,
  }));
}

function formatTime(isoStr) {
  if (!isoStr) return '—';
  const d = new Date(isoStr);
  return d.toLocaleTimeString('en-AU', { hour: '2-digit', minute: '2-digit', hour12: true });
}

function formatDateTime(isoStr) {
  if (!isoStr) return '—';
  const d = new Date(isoStr);
  return d.toLocaleDateString('en-AU', { day: '2-digit', month: 'short', year: 'numeric' }) + ' ' + formatTime(isoStr);
}

function formatDate(isoStr) {
  if (!isoStr) return '—';
  const d = new Date(isoStr);
  return d.toLocaleDateString('en-AU', { day: '2-digit', month: 'short', year: 'numeric' });
}

function formatMins(mins) {
  if (mins === null || mins === undefined || isNaN(mins)) return '—';
  const h = Math.floor(Math.abs(mins) / 60);
  const m = Math.round(Math.abs(mins) % 60);
  const sign = mins < 0 ? '-' : '+';
  if (h === 0) return `${sign}${m}m`;
  return `${sign}${h}h ${m}m`;
}

function formatSLA(mins) {
  if (!mins) return '—';
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  if (h === 0) return `${m} min`;
  if (m === 0) return `${h}h`;
  return `${h}h ${m}m`;
}

function getMonthOptions(data) {
  const months = new Set();
  data.forEach(d => {
    if (d.date) months.add(d.date.substring(0, 7));
  });
  return Array.from(months).sort();
}

